console.log("正在编辑博客类型，skillId = "+skillId);layui.use(["form","layer"],function(){let form=layui.form;let layer=layui.layer;let skill;if(skillId){$.ajax({url:"/skill/"+skillId,method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200&&a.data){skill=a.data[0];form.val("form-linkType",{id:skill.id,name:skill.name,owner:skill.owner,percent:skill.percent});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(form-skill-submit)",function(a){let skill=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/skill/"+skillId,data:{name:skill.name,owner:skill.owner,percent:skill.percent},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false});form.verify({name:function(b,a){let nameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!nameRex.test(b)){return"技能名只能为2-20个字符"}},owner:function(b,a){let ownerRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!ownerRex.test(b)){return"所有者只能为2-20个字符"}}})}else{layer.msg("参数错误",{icon:2})}});